parameters.jsCode:
const xml2js = require('xml2js');
let parsed = {};
xml2js.parseString(items[0].json.data, (err, result) => {
  parsed = result;
});
// Target top 3 trending items
const topItems = parsed.rss.channel[0].item.slice(0, 3);
return topItems.map(item => ({
  json: {
    title: item.title[0],
    link: item.link[0],
    description: item.description[0],
    content: item['content:encoded'] ? item['content:encoded'][0] : item.description[0],
    pubDate: item.pubDate[0],
    image_url: item.enclosure ? item.enclosure[0].$.url : ''
  }
}));

